script:
// --- بداية الكود ---

frappe.ui.form.on('Building Survey', {
    refresh: function(frm) {
        // إخفاء الحقول الفردية فقط لتجنب إخفاء قسم التصميم بالكامل
        frm.toggle_display([
            'full_name', 'phone', 'email', 'current_residence', 'city',
            'project_location', 'has_sketch', 'has_autocad',
            'size_family', 'couples', 'grandchildren', 'girls_under_10',
            'boys_under_10', 'girls_above_14', 'boys_above_14', 'haya'
        ], false);
        
        render_custom_survey(frm);
    }
});

function render_custom_survey(frm) {
    let wrapper = frm.get_field('survey_ui');
    if (!wrapper) return;

    // 1. هيكل التصميم CSS
    let css = `
        <style>
            .custom-survey-wrapper {
                direction: rtl;
                font-family: 'Tajawal', 'Cairo', sans-serif;
                background-color: #f8f9fa;
                padding: 20px;
                color: #333;
            }
            .survey-header-main {
                background-color: #a8b2bc;
                color: #2c3e50;
                padding: 15px;
                font-size: 24px;
                font-weight: bold;
                text-align: right;
                border-radius: 8px 8px 0 0;
                margin-bottom: 20px;
                display: flex;
                align-items: center;
            }
            .survey-section {
                border: 2px solid #5c6c7f;
                border-radius: 8px;
                background: #fff;
                margin-bottom: 20px;
                overflow: hidden;
            }
            .section-title {
                background-color: #5c6c7f;
                color: #fff;
                padding: 10px 15px;
                font-size: 18px;
                font-weight: bold;
                display: inline-block;
                border-radius: 0 0 0 8px;
            }
            .section-content {
                padding: 15px;
            }
            .form-row-custom {
                display: flex;
                align-items: center;
                margin-bottom: 12px;
                border-bottom: 1px dashed #e2e8f0;
                padding-bottom: 8px;
            }
            .form-row-custom label {
                flex: 1;
                font-weight: bold;
                color: #2c3e50;
                margin: 0;
                font-size: 14px;
            }
            .form-row-custom input[type="text"], 
            .form-row-custom input[type="tel"], 
            .form-row-custom input[type="number"] {
                flex: 2;
                border: none;
                border-bottom: 1px solid #ccc;
                background: transparent;
                padding: 5px;
                outline: none;
                font-family: inherit;
            }
            .form-row-custom input[type="number"] {
                text-align: center;
            }
            .form-row-custom input[type="text"]:focus, 
            .form-row-custom input[type="tel"]:focus,
            .form-row-custom input[type="number"]:focus {
                border-bottom: 2px solid #5c6c7f;
            }
            .checkbox-group {
                display: flex;
                flex-direction: column;
                gap: 10px;
            }
            .checkbox-group.horizontal {
                flex-direction: row;
                gap: 20px;
            }
            .checkbox-custom {
                display: flex;
                align-items: center;
                cursor: pointer;
            }
            .checkbox-custom input {
                margin-left: 8px;
                width: 18px;
                height: 18px;
                cursor: pointer;
            }
            .map-container {
                margin-top: 15px;
                margin-bottom: 15px;
                border: 1px solid #ccc;
                border-radius: 8px;
                padding: 10px;
                background: #fdfdfd;
            }
            .grid-2-cols {
                display: grid;
                grid-template-columns: 1fr 1fr;
                gap: 15px;
            }
        </style>
    `;

    // 2. هيكل الـ HTML مربوط بالحقول الجديدة
    let html = `
        <div class="custom-survey-wrapper">
            
            <div class="survey-header-main">
                نموذج استبيان مبنى سكني
            </div>

            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 20px;">
                
                <div>
                    <div class="survey-section">
                        <div class="section-title">معلومات خاصة بالمشروع</div>
                        <div class="section-content">
                            <div class="form-row-custom">
                                <label>أين يقع المشروع:</label>
                                <input type="text" id="ui_project_location" value="${frm.doc.project_location || ''}">
                            </div>

                            <div class="map-container" id="custom_map_wrapper">
                                <label style="font-weight:bold; color:#2c3e50; margin-bottom:10px; display:block;">تحديد الموقع في الخريطة:</label>
                            </div>
                            
                            <div class="form-row-custom">
                                <label>هل يوجد رسم كروكي للأرض؟</label>
                                <div class="checkbox-group horizontal">
                                    <label class="checkbox-custom"><input type="radio" name="has_sketch" value="نعم" ${frm.doc.has_sketch === 'نعم' ? 'checked' : ''}> نعم</label>
                                    <label class="checkbox-custom"><input type="radio" name="has_sketch" value="لا" ${frm.doc.has_sketch === 'لا' ? 'checked' : ''}> لا</label>
                                </div>
                            </div>

                            <div class="form-row-custom">
                                <label>هل يوجد نسخة إلكترونية (AutoCAD)؟</label>
                                <div class="checkbox-group horizontal">
                                    <label class="checkbox-custom"><input type="radio" name="has_autocad" value="نعم" ${frm.doc.has_autocad === 'نعم' ? 'checked' : ''}> نعم</label>
                                    <label class="checkbox-custom"><input type="radio" name="has_autocad" value="لا" ${frm.doc.has_autocad === 'لا' ? 'checked' : ''}> لا</label>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div class="survey-section">
                        <div class="section-title">معلومات خاصة بالزبون</div>
                        <div class="section-content">
                            <div style="text-align: center; margin-bottom: 15px; color: #5c6c7f; font-weight: bold;">حجم الأسرة</div>
                            <div class="checkbox-group">
                                <label class="checkbox-custom">
                                    <input type="radio" name="size_family" value="أسرة حديثة متكونة من زوجين" ${frm.doc.size_family === 'أسرة حديثة متكونة من زوجين' ? 'checked' : ''}>
                                    أسرة حديثة متكونة من زوجين
                                </label>
                                <label class="checkbox-custom">
                                    <input type="radio" name="size_family" value="أسرة حديثة متكونة من زوجين وأطفال" ${frm.doc.size_family === 'أسرة حديثة متكونة من زوجين وأطفال' ? 'checked' : ''}>
                                    أسرة حديثة متكونة من زوجين وأطفال
                                </label>
                                <label class="checkbox-custom">
                                    <input type="radio" name="size_family" value="أسرة متكونة من زوجين وأبناء" ${frm.doc.size_family === 'أسرة متكونة من زوجين وأبناء' ? 'checked' : ''}>
                                    أسرة متكونة من زوجين وأبناء
                                </label>
                                <label class="checkbox-custom">
                                    <input type="radio" name="size_family" value="عائلة متكونة من زوجين وأبناء وأحفاد" ${frm.doc.size_family === 'عائلة متكونة من زوجين وأبناء وأحفاد' ? 'checked' : ''}>
                                    عائلة متكونة من زوجين وأبناء وأحفاد
                                </label>
                            </div>

                            <hr style="border-top: 1px dashed #ccc; margin: 15px 0;">
                            
                            <div style="text-align: center; margin-bottom: 15px; color: #5c6c7f; font-weight: bold;">كم عدد أفراد مستخدمي المبنى من:</div>
                            <div class="grid-2-cols">
                                <div class="form-row-custom">
                                    <label>أزواج:</label>
                                    <input type="number" id="ui_couples" value="${frm.doc.couples || ''}" min="0">
                                </div>
                                <div class="form-row-custom">
                                    <label>أحفاد:</label>
                                    <input type="number" id="ui_grandchildren" value="${frm.doc.grandchildren || ''}" min="0">
                                </div>
                                <div class="form-row-custom">
                                    <label>أولاد (أصغر من 10 سنة):</label>
                                    <input type="number" id="ui_boys_under_10" value="${frm.doc.boys_under_10 || ''}" min="0">
                                </div>
                                <div class="form-row-custom">
                                    <label>بنات (أصغر من 10 سنة):</label>
                                    <input type="number" id="ui_girls_under_10" value="${frm.doc.girls_under_10 || ''}" min="0">
                                </div>
                                <div class="form-row-custom">
                                    <label>أولاد (أكبر من 14 سنة):</label>
                                    <input type="number" id="ui_boys_above_14" value="${frm.doc.boys_above_14 || ''}" min="0">
                                </div>
                                <div class="form-row-custom">
                                    <label>بنات (أكبر من 14 سنة):</label>
                                    <input type="number" id="ui_girls_above_14" value="${frm.doc.girls_above_14 || ''}" min="0">
                                </div>
                            </div>

                            <hr style="border-top: 1px dashed #ccc; margin: 15px 0;">

                            <div style="margin-bottom: 15px; color: #5c6c7f; font-weight: bold;">نمط الحياة و الخصوصية (احتمالية ارتداد زوار للمنزل):</div>
                            <div class="checkbox-group">
                                <label class="checkbox-custom">
                                    <input type="radio" name="haya" value="اجتماعي جداً" ${frm.doc.haya === 'اجتماعي جداً' ? 'checked' : ''}>
                                    اجتماعي جداً (احتمال وجود حركة زوار شبه دائمة في المنزل)
                                </label>
                                <label class="checkbox-custom">
                                    <input type="radio" name="haya" value="اجتماعي" ${frm.doc.haya === 'اجتماعي' ? 'checked' : ''}>
                                    اجتماعي (احتمالية وجود عدد زيارات قليلة للمنزل)
                                </label>
                                <label class="checkbox-custom">
                                    <input type="radio" name="haya" value="غير اجتماعي" ${frm.doc.haya === 'غير اجتماعي' ? 'checked' : ''}>
                                    غير اجتماعي (وجود زيارات في المناسبات فقط)
                                </label>
                            </div>

                        </div>
                    </div>
                </div>

                <div>
                    <div class="survey-section">
                        <div class="section-title" style="float: right; border-radius: 0 8px 0 0;">معلومات التواصل</div>
                        <div style="clear: both;"></div>
                        <div class="section-content">
                            <div class="form-row-custom">
                                <label>الإسم:</label>
                                <input type="text" id="ui_full_name" value="${frm.doc.full_name || ''}">
                            </div>
                            <div class="form-row-custom">
                                <label>رقم الهاتف:</label>
                                <input type="tel" id="ui_phone" value="${frm.doc.phone || ''}">
                            </div>
                            <div class="form-row-custom">
                                <label>البريد الإلكتروني:</label>
                                <input type="text" id="ui_email" value="${frm.doc.email || ''}">
                            </div>
                            <div class="form-row-custom">
                                <label>مكان السكن الحالي:</label>
                                <input type="text" id="ui_current_residence" value="${frm.doc.current_residence || ''}">
                            </div>
                            <div class="form-row-custom">
                                <label>من أي مدينة:</label>
                                <input type="text" id="ui_city" value="${frm.doc.city || ''}">
                            </div>
                        </div>
                    </div>
                </div>

            </div>
        </div>
    `;

    wrapper.$wrapper.html(css + html);

    // دالة نقل حقل الخريطة إلى داخل التصميم
    setTimeout(() => {
        if (frm.fields_dict.gg && frm.fields_dict.gg.wrapper) {
            $(frm.fields_dict.gg.wrapper).appendTo(wrapper.$wrapper.find('#custom_map_wrapper'));
        }
    }, 100);

    bind_survey_events(frm, wrapper.$wrapper);
}

function bind_survey_events(frm, $wrapper) {
    // 1. ربط الحقول النصية والرقمية
    const text_fields = [
        'full_name', 'phone', 'email', 'current_residence', 'city', 'project_location',
        'couples', 'grandchildren', 'boys_under_10', 'girls_under_10', 'boys_above_14', 'girls_above_14'
    ];
    
    text_fields.forEach(field => {
        $wrapper.find(`#ui_${field}`).on('change', function() {
            frm.set_value(field, $(this).val());
        });
    });

    // 2. ربط حقول الاختيار (Radio Buttons)
    const select_fields = ['has_sketch', 'has_autocad', 'size_family', 'haya'];
    
    select_fields.forEach(field => {
        $wrapper.find(`input[name="${field}"]`).on('change', function() {
            frm.set_value(field, $(this).val());
        });
    });
}

// --- نهاية الكود ---
